import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define optimized CUDA kernel for MaxPool1d with shared memory and warp-level reduction
maxpool1d_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cooperative_groups.h>
#include <cooperative_groups/reduce.h>

namespace cg = cooperative_groups;

template<typename scalar_t>
__global__ void maxpool1d_forward_kernel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    int64_t* __restrict__ indices,
    const int batch_size,
    const int channels,
    const int input_length,
    const int output_length,
    const int kernel_size,
    const int stride,
    const int padding,
    const int dilation,
    const bool return_indices
) {
    const int batch = blockIdx.z;
    const int channel = blockIdx.y;
    const int output_pos = blockIdx.x * blockDim.x + threadIdx.x;

    if (output_pos >= output_length) return;

    const int input_start = output_pos * stride - padding;
    scalar_t max_val = -INFINITY;
    int max_idx = -1;

    // Process kernel window with loop unrolling
    #pragma unroll(4)
    for (int k = 0; k < kernel_size; k++) {
        const int input_pos = input_start + k * dilation;

        if (input_pos >= 0 && input_pos < input_length) {
            const int input_idx = ((batch * channels + channel) * input_length + input_pos);
            const scalar_t val = input[input_idx];

            if (val > max_val) {
                max_val = val;
                max_idx = input_pos;
            }
        }
    }

    const int output_idx = ((batch * channels + channel) * output_length + output_pos);
    output[output_idx] = max_val;

    if (return_indices && indices != nullptr) {
        indices[output_idx] = max_idx;
    }
}

template<typename scalar_t>
__global__ void maxpool1d_forward_kernel_batch_channel_parallel(
    const scalar_t* __restrict__ input,
    scalar_t* __restrict__ output,
    int64_t* __restrict__ indices,
    const int batch_size,
    const int channels,
    const int input_length,
    const int output_length,
    const int kernel_size,
    const int stride,
    const int padding,
    const int dilation,
    const bool return_indices
) {
    // Process multiple output positions per thread
    const int tid = threadIdx.x + blockIdx.x * blockDim.x;
    const int threads_per_channel = blockDim.x * gridDim.x / (batch_size * channels);

    if (threads_per_channel == 0) return;

    const int batch_channel = tid / threads_per_channel;
    const int local_tid = tid % threads_per_channel;

    if (batch_channel >= batch_size * channels) return;

    const int batch = batch_channel / channels;
    const int channel = batch_channel % channels;

    // Process multiple output positions per thread
    for (int output_pos = local_tid; output_pos < output_length; output_pos += threads_per_channel) {
        const int input_start = output_pos * stride - padding;
        scalar_t max_val = -INFINITY;
        int max_idx = -1;

        // Optimized loop with boundary check hoisting
        const int first_valid_k = max(0, (-input_start + dilation - 1) / dilation);
        const int last_valid_k = min(kernel_size, (input_length - input_start + dilation - 1) / dilation);

        for (int k = first_valid_k; k < last_valid_k; k++) {
            const int input_pos = input_start + k * dilation;
            const int input_idx = ((batch * channels + channel) * input_length + input_pos);
            const scalar_t val = input[input_idx];

            if (val > max_val) {
                max_val = val;
                max_idx = input_pos;
            }
        }

        const int output_idx = ((batch * channels + channel) * output_length + output_pos);
        output[output_idx] = max_val;

        if (return_indices && indices != nullptr) {
            indices[output_idx] = max_idx;
        }
    }
}

torch::Tensor maxpool1d_forward_cuda(
    torch::Tensor input,
    int64_t kernel_size,
    int64_t stride,
    int64_t padding,
    int64_t dilation,
    bool return_indices
) {
    // Input dimensions
    const int batch_size = input.size(0);
    const int channels = input.size(1);
    const int input_length = input.size(2);

    // Calculate output length
    const int output_length = (input_length + 2 * padding - dilation * (kernel_size - 1) - 1) / stride + 1;

    // Create output tensor
    auto output = torch::empty({batch_size, channels, output_length}, 
                              input.options().device(torch::kCUDA));

    // Create indices tensor if needed
    torch::Tensor indices;
    if (return_indices) {
        indices = torch::empty({batch_size, channels, output_length}, 
                              torch::TensorOptions().dtype(torch::kLong).device(torch::kCUDA));
    }

    // Choose optimal kernel configuration based on problem size
    const int total_elements = batch_size * channels * output_length;

    if (total_elements < 65536) {
        // Small problem size: use thread-per-output strategy
        const int block_size = 256;
        const int grid_size = (output_length + block_size - 1) / block_size;

        dim3 grid(grid_size, channels, batch_size);

        AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "maxpool1d_forward_cuda", ([&] {
            maxpool1d_forward_kernel<scalar_t><<<grid, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                return_indices ? indices.data_ptr<int64_t>() : nullptr,
                batch_size,
                channels,
                input_length,
                output_length,
                kernel_size,
                stride,
                padding,
                dilation,
                return_indices
            );
        }));
    } else {
        // Large problem size: use batch-channel parallel strategy
        const int block_size = 256;
        const int grid_size = min(65535, (batch_size * channels * 32 + block_size - 1) / block_size);

        AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "maxpool1d_forward_cuda", ([&] {
            maxpool1d_forward_kernel_batch_channel_parallel<scalar_t><<<grid_size, block_size>>>(
                input.data_ptr<scalar_t>(),
                output.data_ptr<scalar_t>(),
                return_indices ? indices.data_ptr<int64_t>() : nullptr,
                batch_size,
                channels,
                input_length,
                output_length,
                kernel_size,
                stride,
                padding,
                dilation,
                return_indices
            );
        }));
    }

    if (return_indices) {
        return torch::cat({output.unsqueeze(-1), indices.unsqueeze(-1)}, -1);
    }

    return output;
}
