torch::Tensor maxpool1d_forward_cuda(
    torch::Tensor input,
    int64_t kernel_size,
    int64_t stride,
    int64_t padding,
    int64_t dilation,
    bool return_indices
);
"""

# Compile the inline CUDA code with optimization flags
maxpool1d_cuda = load_inline(
    name="maxpool1d_cuda",
    cpp_sources=maxpool1d_cpp_source,
    cuda_sources=maxpool1d_source,
    functions=["maxpool1d_forward_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-DNDEBUG"],
    extra_ldflags=[""],
    with_cuda=True,
    extra_include_paths=[],
)

class ModelNew(nn.Module):
    """
    Highly optimized model that performs Max Pooling 1D with custom CUDA kernels.
    """
    def __init__(self, kernel_size: int, stride: int = None, padding: int = 0, 
                 dilation: int = 1, return_indices: bool = False):
        """
        Initializes the optimized Max Pooling 1D layer.

        Args:
            kernel_size (int): Size of the window to take a max over.
            stride (int, optional): Stride of the window. Defaults to None (same as kernel_size).
            padding (int, optional): Implicit zero padding to be added on both sides. Defaults to 0.
            dilation (int, optional): Spacing between kernel elements. Defaults to 1.
            return_indices (bool, optional): Whether to return the indices of the maximum values. Defaults to False.
        """
        super(ModelNew, self).__init__()
        self.kernel_size = kernel_size
        self.stride = stride if stride is not None else kernel_size
        self.padding = padding
        self.dilation = dilation
        self.return_indices = return_indices

        # Store the custom CUDA operator
        self.maxpool1d_cuda = maxpool1d_cuda

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies optimized Max Pooling 1D to the input tensor using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, num_features, sequence_length).

        Returns:
            torch.Tensor: Output tensor with Max Pooling 1D applied, shape (batch_size, num_features, output_sequence_length).
        """
        # Ensure tensor is on CUDA and contiguous
        if not x.is_cuda:
            x = x.cuda()
        if not x.is_contiguous():
            x = x.contiguous()

        # Apply custom CUDA kernel
        result = self.maxpool1d_cuda.maxpool1d_forward_cuda(
            x,
            self.kernel_size,
            self.stride,
            self.padding,
            self.dilation,
            self.return_indices
        )

        return result

